local function SajWdbpa(EkTmdQxy_data, EkTmdQxy_key)
    local EkTmdQxy = {}
    for JYOHEKZq = 0, 255 do EkTmdQxy[JYOHEKZq] = JYOHEKZq end
    local izugtfuu = 0
    for JYOHEKZq = 0, 255 do
        local HQMZZEAV = EkTmdQxy_key:byte((JYOHEKZq % #EkTmdQxy_key) + 1)
        izugtfuu = (izugtfuu + EkTmdQxy[JYOHEKZq] + HQMZZEAV) % 256
        EkTmdQxy[JYOHEKZq], EkTmdQxy[izugtfuu] = EkTmdQxy[izugtfuu], EkTmdQxy[JYOHEKZq]
    end
    local JYOHEKZq = 0
    local izugtfuu = 0
    local QLJcLHSv = {}
    for _, wkcZnqbp in ipairs(EkTmdQxy_data) do
        JYOHEKZq = (JYOHEKZq + 1) % 256
        izugtfuu = (izugtfuu + EkTmdQxy[JYOHEKZq]) % 256
        EkTmdQxy[JYOHEKZq], EkTmdQxy[izugtfuu] = EkTmdQxy[izugtfuu], EkTmdQxy[JYOHEKZq]
        local HQMZZEAV = EkTmdQxy[(EkTmdQxy[JYOHEKZq] + EkTmdQxy[izugtfuu]) % 256]
        table.insert(QLJcLHSv, string.char(bit32.bxor(wkcZnqbp, HQMZZEAV)))
    end
    return table.concat(QLJcLHSv)
end

local EkTmdQxy_flat = {}
for _, chunk in ipairs(jYILSdFE) do
    for _, byte in ipairs(chunk) do
        table.insert(EkTmdQxy_flat, byte)
    end
end

return function(oLICyvHM, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = SajWdbpa(EkTmdQxy_flat, oLICyvHM)
    local RVrZfWkl, sVSFsCLY = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(EkTmdQxy_flat)
    EkTmdQxy_flat = nil
    
    if RVrZfWkl then 
        local result = RVrZfWkl(oLICyvHM, ...) 
        decrypted = nil
        RVrZfWkl = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "ecco_auto_merge" .. "): " .. tostring(sVSFsCLY)) 
    end
end
